// 解析 Google Docs 知识库内容
const content = $json.data || $json;

// 解析 Markdown 内容为文档数组
const sections = content.split(/(?=^### \*\*)/m);
const documents = [];

sections.forEach((section, index) => {
  if (section.trim()) {
    const titleMatch = section.match(/^### \*\*(\d+\.\s*[^*]+)\*\*/m);
    const title = titleMatch ? titleMatch[1] : `Section ${index + 1}`;

    let cleanContent = section
      .replace(/^### \*\*.*?\*\*/gm, '')
      .replace(/^```[\s\S]*?```/gm, (match) => {
        return match.replace(/^```sql?\s*/gm, '').replace(/```$/gm, '');
      })
      .replace(/^#+ /gm, '')
      .trim();

    if (cleanContent.length > 50) {
      documents.push({
        content: cleanContent,
        metadata: {
          title: title,
          type: 'knowledge-base',
          source: 'google-docs',
          section: index + 1
        }
      });
    }
  }
});

// 合并所有内容为单个知识库字符串
const knowledgeBaseContent = documents.map(doc => 
  `## ${doc.metadata.title}\n${doc.content}`
).join('\n\n');

return {
  json: {
    documents: documents,
    knowledgeBaseContent: knowledgeBaseContent,
    documentCount: documents.length,
    originalMessage: $('Telegram Trigger').item.json.message.text || 'Unknown message',
    chatId: $('Telegram Trigger').item.json.message.chat.id || '',
    messageId: $('Telegram Trigger').item.json.message.message_id || ''
  }
};

// 处理AI Agent输出，提取SQL并执行查询
const inputData = $json;

// 检查AI Agent的输出结构
let aiOutput;
if (inputData.output) {
  aiOutput = inputData.output;
} else if (inputData.text) {
  try {
    const jsonMatch = inputData.text.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      aiOutput = JSON.parse(jsonMatch[0]);
    }
  } catch (error) {
    aiOutput = { error: 'JSON解析失败: ' + error.message };
  }
} else {
  aiOutput = { error: 'AI Agent输出不完整' };
}

// 提取关键信息
const queryType = aiOutput.queryType || '未知场景';
const confidence = aiOutput.confidence || '低';
const extractedInfo = aiOutput.extractedInfo || {};
const generatedSQL = aiOutput.generatedSQL || '';
const canExecute = aiOutput.canExecute || false;

// 返回结果
return {
  json: {
    queryType: queryType,
    confidence: confidence,
    extractedInfo: extractedInfo,
    generatedSQL: generatedSQL,
    canExecute: canExecute,
    originalMessage: $('Telegram Trigger').item.json.message.text || 'Unknown message',
    chatId: $('Telegram Trigger').item.json.message.chat.id || '',
    messageId: $('Telegram Trigger').item.json.message.message_id || '',
    // 调试信息
    debug: {
      hasOutput: !!inputData.output,
      hasText: !!inputData.text,
      parsedOutput: aiOutput,
      knowledgeBaseUsed: !!inputData.knowledgeBaseContent
    }
  }
};

// 处理查询结果
const data = $json;

if (data.success && data.result && data.result.data) {
  const queryData = data.result.data;

  return {
    json: {
      success: true,
      queryId: data.queryId,
      status: data.status,
      rowCount: queryData.rowCount || 0,
      totalRows: queryData.totalRows || 0,
      executionTime: data.result.executionTime,
      data: queryData,
      message: `查询成功！返回 ${queryData.rowCount || 0} 条记录`,
      timestamp: new Date().toISOString()
    }
  };
} else {
  return {
    json: {
      success: false,
      queryId: data.queryId,
      status: data.status,
      error: data.error || '查询失败',
      message: data.message || '查询执行失败',
      timestamp: new Date().toISOString()
    }
  };
}

